mapper.select:
SELECT t1.ID, t1.CONTRACT_NAME, t1.CONTRACT_CODE, t1.CONTRACT_AMOUNT, t1.START_DATE, t1.END_DATE, t1.APPLY_SCOPE, t1.STATUS, t1.CONTRACT_TYPE, t1.USE_COMPANY_ID, t1.USE_COMPANY_NAME, t3.EXTERNAL_COMPANY_ID, t3.UNIT_NAME, t2.DICT_LABEL contractTypeLabel
FROM E_COST_CONTRACT_INFO t1 LEFT JOIN M_DICT_DATA t2 ON t2.DICT_VALUE = t1.CONTRACT_TYPE AND t2.DICT_TYPE = 'CONTRACT_TYPE' LEFT JOIN E_M_EQUIP_REPAIR_CONTRACT t3 ON t1.EXTERNAL_COMPANY_ID = t3.EXTERNAL_COMPANY_ID and deleted = 0 where 1 = 1
and CONTRACT_NAME like #{contractNameLike}
and CONTRACT_CODE like #{contractCodeLike}
AND START_DATE >= #{startDate}
and END_DATE <= #{endDate}
order by t1.CREATED_TIME DESC
